# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)
db = client['content_management']

# User profile collection
users = db['users']

# Document collection
documents = db['documents']

# User registration
@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    users.insert_one(data)
    return jsonify({'message': 'User registered successfully'}), 201

# Document upload
@app.route('/upload', methods=['POST'])
def upload():
    data = request.get_json()
    documents.insert_one(data)
    return jsonify({'message': 'Document uploaded successfully'}), 201

# Document query
@app.route('/query', methods=['GET'])
def query():
    query = request.args.get('query')
    results = documents.find({'title': {'$regex': query}})
    return jsonify(list(results)), 200

# Document aggregation
@app.route('/aggregate', methods=['GET'])
def aggregate():
    pipeline = [
        {'$match': {'category': 'news'}},
        {'$group': {'_id': '$author', 'count': {'$sum': 1}}}
    ]
    results = documents.aggregate(pipeline)
    return jsonify(list(results)), 200

if __name__ == '__main__':
    app.run(debug=True)